(window.webpackJsonp=window.webpackJsonp||[]).push([[353],{980:function(n,r){n.exports="\x3c!-- \r\ntitle: 06-数据库\r\nsort: \r\n--\x3e \r\n\r\n> 高速查询数据的方法\r\n\r\n## 为什么使用Mysql\r\n\r\n> 你要建立一个网站储存用户数据\r\n>\r\n> 只学过c语言的人可能会说，用链表实现。\r\n>\r\n> 学过python的人可能会说，存成csv。\r\n>\r\n> 但加入用户量高达万人，查询用户遍历链表及文件是一件极为痛苦的事情。\r\n>\r\n> 而使用关系型数据库吗，索引的查询速度是极为高效的。\r\n>\r\n> 前两天徐学长搞社工库，把几亿条数据传到sql中，花费数小时，而传完后查询仅需几秒。\r\n\r\n## 基础语法\r\n\r\n> 关键词\r\n\r\n| 命令     | 用法                                                |\r\n| -------- | --------------------------------------------------- |\r\n| `select` | 选择，可理解为读取并输出。<br />`select version();` |\r\n| `show`   | 展示数据库信息                                      |\r\n|          |                                                     |\r\n|          |                                                     |\r\n\r\n### 改密码\r\n\r\n```mysql\r\nset password='password';\r\n# 报错？自己搜！\r\n# 运行成功别忘记刷新\r\nflush privileges;\r\n```\r\n\r\n## 作业\r\n\r\n1. 修改数据库密码。\r\n2. 读取我程序操作的表并拍照发给我。"}}]);